"""
Cart item - single responsibility: represent a product in the cart with its discount.
"""

from srp_product import SrpProduct


class SrpCartItem:
    def __init__(self, product: SrpProduct, discount_amount: float):
        self.product = product
        self.discount_amount = discount_amount

    def get_product(self) -> SrpProduct:
        return self.product

    def get_discount_amount(self) -> float:
        return self.discount_amount

""" Data manager - single responsibility: persist data to storage. """
from typing import List from srp_product import SrpProduct
class SrpDataManager: def save_db(self, products: List[SrpProduct]) -> None: """ Save products to the database. """ for product in products: print(f"Saving database... {product.get_price()}")

""" Inventory adjustment - single responsibility: manage inventory updates. """
from srp_product import SrpProduct
class SrpInventoryAdjustment: def update_available_qty(self, product: SrpProduct) -> None: """ Update available quantity for a product. """ print(f"Update Available Qty for {product.get_name()}")
def update_reserved_qty(self, product: SrpProduct) -> None: """ Update reserved quantity for a product. """ print(f"Update Reserved Qty for {product.get_name()}")

"""
Product domain model - single responsibility: hold product data.
"""


class SrpProduct:
    def __init__(self, name: str, price: float):
        self.name = name
        self.price = price

    def get_name(self) -> str:
        return self.name

    def get_price(self) -> float:
        return self.price

""" Product Repository - single responsibility: manage the list of products. """
from typing import List from srp_product import SrpProduct
class SrpProductRepository: def __init__(self): self.products: List[SrpProduct] = []
def add_product(self, name: str, price: float) -> None: """ Add a product to the repository by providing product details. """ product = SrpProduct(name, price) self.products.append(product) print(f"Product added: {name} - ${price}")
def get_products(self) -> List[SrpProduct]: """ Return the list of all products. """ return list(self.products)
def get_product_count(self) -> int: """ Return the number of products in the repository. """ return len(self.products)
def display_products(self) -> None: """ Display all products in the repository. """ if not self.products: print("No products in repository.") return
print("\n=== Products in Repository ===") for i, product in enumerate(self.products, 1): print(f"{i}. {product.get_name()} - ${product.get_price()}")
